  ('pukao-7fec267e-moex-00028', 'pukao-7fec267e', 'pukao-7fec267e-moex-114-4dccc0e6', 'sub-pukao-7fec267e-02', NULL, 'single_choice', '下列何者不是公部門管理與私部門管理之差異？', '["公部門管理具有獨占特質，而企業管理強調競爭", "公部門管理較可能會有金魚缸效應（goldfish-bowleffect）", "公部門的決策權力較為集中，而企業的決策程序較為分散與繁複", "企業的組織目標較明確，績效較容易衡量"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:13+00:00", "source_pdf_sha1": "c09432b9175f", "answer_pdf_sha1": "dc420f888dc7", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "401", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政學概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般行政"}'::jsonb, NULL),
